const schemaDescription = `
You must return a single valid JSON object matching this exact structure.
No preamble, no markdown fences, no explanation — only the raw JSON.

Required top-level keys and their types:

company_overview: object with keys:
  name (string), industry (string), primary_services (array of strings),
  mission (string), vision (string), tagline (string)

core_services: array of objects, each with:
  name (string), description (string), key_deliverables (array of strings),
  key_topics (array of strings), client_outcomes (array of strings)

target_audience: array of objects, each with:
  persona_name (string), role (string), company_type (string),
  pain_point (string), goal (string), buys_service (string)

primary_client_types: array of objects, each with:
  type (string), description (string), pain_points (array of strings)

customer_pain_points: array of strings

value_propositions: object with:
  reasons_clients_choose_us (array of strings), differentiators (array of strings)

competitor_differentiation: object with:
  vs_large_consulting_firms (array of strings),
  vs_generic_agencies (array of strings),
  vs_diy_tools (array of strings),
  key_positioning_statement (string)

brand_voice: object with:
  tone (array of strings), messaging_themes (array of strings),
  use_language_like (array of strings), avoid_language_like (array of strings)

prohibited_phrases: array of strings

key_content_topics: array of objects, each with:
  service_name (string), topics (array of strings)

seo_keywords: object with:
  primary (array of strings), secondary (array of strings), long_tail (array of strings)

content_strategy: object with:
  monthly_targets: object with keys blogs (integer), linkedin_posts (integer),
    educational_social_posts (integer), email_newsletters (integer), long_form_guides (integer)
  content_pillars (array of strings)

marketing_channels: object with:
  primary (array of strings), secondary (array of strings)

industry_trends: array of strings

technical_integrations: array of strings

internal_workflow: array of objects, each with:
  role (string), responsibility (string)

Fill every field thoroughly. No empty strings. No placeholders.
`;
const input = $input.first().json;
const textToArray = (text) => {
  if (!text) return [];
  return text.split('
').map(l => l.trim()).filter(l => l.length > 0);
};
const parseKeyValue = (text, keyName, valName) => {
  return textToArray(text).map(line => {
    const parts = line.split(':');
    return {  [keyName]: parts[0]?.trim() || '',  [valName]: parts[1]?.trim() || ''};
  }).filter(item => item[keyName]);
};
const coreServices = parseKeyValue(input['Core Services (Format: Name: Description, one per line)'], 'name', 'description');
const targetAudience = parseKeyValue(input['Target Audience (Format: Persona: Role, one per line)'], 'persona_name', 'role');
const clientProblems = textToArray(input['Client Problems (One per line)']);
const whyChooseUs = textToArray(input['Why Choose Us (One per line)']);

const userMessage = `Generate a complete Master Business Context document based on the company details below.

Company Name: ${input['Company Name']}
Industry: ${input['Industry']}
Primary Service: ${input['Primary Services']}
Mission: ${input['Mission']}
Vision: ${input['Vision']}
Tagline: ${input['Tagline']}

Core Services:
${JSON.stringify(coreServices)}

Target Audience Names/Roles:
${JSON.stringify(targetAudience)}

Common Problems Clients Face:
${JSON.stringify(clientProblems)}

Why Clients Choose Us:
${JSON.stringify(whyChooseUs)}`;

const prompt = {
  systemInstruction: `You are a professional business content writer specializing in AI consulting companies.
Your job is to generate complete, structured Master Business Context documents.
Always write in a confident, expert, and approachable tone.
Never use generic clichés like "game-changer", "leverage", "seamless", "cutting-edge",
"revolutionize", "unlock potential", "synergy", "best-in-class", "holistic approach".
Make every section specific and actionable — no filler content.

${schemaDescription}`,
  userMessage,
  "generationConfig": {
    "temperature": 0.4,
    "maxOutputTokens": 8192,
    "responseMimeType": "application/json"
  }
};
return { json: prompt };

const items = $input.first().json
const text = items.content?.parts?.[0]?.text ?? '';
const cleanJson = text.replace(/```json|```/g, "").trim();
const response = JSON.parse(cleanJson)
return {response}

const inputJson = [$input.first().json];

function generateMarkdownFromData(jsonData) {
  const data = jsonData[0].response;
  let md = "# AI Agency – Master Business Context
";
  md += "Version: 2.0
";
  md += `Last Updated: ${new Date().getFullYear()}

---

`;
  const renderList = (items) => items.map(item => `- ${item}`).join('
');

  if (data.company_overview) {
    const co = data.company_overview;
    md += `# Company Overview

Company Name: ${co.name}
Industry: ${co.industry}
Primary Services: ${co.primary_services.join(', ')}

Mission:
${co.mission}

Vision:
${co.vision}

Tagline:
${co.tagline}

---

`;
  }
  if (data.core_services) {
    md += `# Core Services

`;
    data.core_services.forEach((svc, i) => {
      md += `## ${i + 1}. ${svc.name}

Description:
${svc.description}

`;
      if (svc.key_deliverables) md += `Key Deliverables:
${renderList(svc.key_deliverables)}

`;
      if (svc.key_topics) md += `Key Topics:
${renderList(svc.key_topics)}

`;
      if (svc.client_outcomes) md += `Client Outcomes:
${renderList(svc.client_outcomes)}

`;
      md += `---

`;
    });
  }
  if (data.target_audience) {
    md += `# Target Audience

## Client Personas

`;
    data.target_audience.forEach((aud, i) => {
      md += `### Persona ${i + 1} – ${aud.persona_name}
Role: ${aud.role}
Company: ${aud.company_type}
Pain: ${aud.pain_point}
Goal: ${aud.goal}
Buys: ${aud.buys_service}

`;
    });
    md += `---

`;
  }
  if (data.primary_client_types) {
    md += `# Primary Client Types

`;
    data.primary_client_types.forEach((c, i) => {
      md += `## ${i + 1}. ${c.type}
${c.description}

Pain Points:
${renderList(c.pain_points)}

`;
    });
    md += `---

`;
  }
  if (data.customer_pain_points) md += `# Customer Pain Points

${renderList(data.customer_pain_points)}

---

`;
  if (data.value_propositions) {
    md += `# Value Propositions

Why Clients Choose Us:
${renderList(data.value_propositions.reasons_clients_choose_us)}

Differentiators:
${renderList(data.value_propositions.differentiators)}

---

`;
  }
  if (data.competitor_differentiation) {
    const cd = data.competitor_differentiation;
    md += `# Competitor Differentiation

vs. Large Consulting Firms:
${renderList(cd.vs_large_consulting_firms)}

vs. Generic IT Agencies:
${renderList(cd.vs_generic_agencies)}

vs. DIY/Pure Automation Tools:
${renderList(cd.vs_diy_tools)}

Key Positioning Statement:
${cd.key_positioning_statement}

---

`;
  }
  if (data.brand_voice) {
    const bv = data.brand_voice;
    md += `# Brand Voice & Messaging

Tone:
${renderList(bv.tone)}

Messaging Themes:
${renderList(bv.messaging_themes)}

Use language like this:
${renderList(bv.use_language_like)}

Avoid language like this:
${renderList(bv.avoid_language_like)}

---

`;
  }
  if (data.prohibited_phrases) md += `# Prohibited Phrases & Clichés

${renderList(data.prohibited_phrases)}

---

`;
  if (data.key_content_topics) {
    md += `# Key Content Topics

`;
    data.key_content_topics.forEach(tg => { md += `## ${tg.service_name} Topics
${renderList(tg.topics)}

`; });
    md += `---

`;
  }
  if (data.seo_keywords) {
    const seo = data.seo_keywords;
    md += `# SEO Keywords

Primary:
${renderList(seo.primary)}

Secondary:
${renderList(seo.secondary)}

Long-Tail:
${renderList(seo.long_tail)}

---

`;
  }
  if (data.content_strategy) {
    const cs = data.content_strategy;
    md += `# Content Strategy

## Monthly Content Targets
Blogs: ${cs.monthly_targets.blogs}
LinkedIn Posts: ${cs.monthly_targets.linkedin_posts}
Educational Social Posts: ${cs.monthly_targets.educational_social_posts}
Email Newsletters: ${cs.monthly_targets.email_newsletters}
Long-Form Guides: ${cs.monthly_targets.long_form_guides}

## Content Pillars
`;
    cs.content_pillars.forEach((p, i) => { md += `${i + 1}. ${p}
`; });
    md += `
---

`;
  }
  if (data.marketing_channels) {
    md += `# Marketing Channels

Primary:
${renderList(data.marketing_channels.primary)}

Secondary:
${renderList(data.marketing_channels.secondary)}

---

`;
  }
  if (data.industry_trends) md += `# Industry Trends

${renderList(data.industry_trends)}

---

`;
  if (data.technical_integrations) md += `# Technical Integrations

${renderList(data.technical_integrations)}

---

`;
  if (data.internal_workflow) {
    md += `# Internal Workflow

## Team Roles

`;
    data.internal_workflow.forEach(m => { md += `${m.role}:
${m.responsibility}

`; });
    md += `---

`;
  }
  md += `# End of File
`;
  return md;
}

const finalMarkdown = generateMarkdownFromData(inputJson);
return {data: finalMarkdown}

const items = $input.all();
const mdItem      = items.find(i => i.json.master_data !== undefined);
const gaItem      = items.find(i => i.json.rows !== undefined || i.json.error !== undefined);
const trendsItem  = items.find(i => i.json.trends_data !== undefined);
const md     = mdItem?.json?.master_data ?? '';
const ga     = gaItem?.json ?? {};
const trends = trendsItem?.json?.trends_data ?? '';
if (!md) throw new Error('Fetch Master MD returned empty — check the URL and HTTP node.');
function extractCompanyName(md) {
  const overview = extractSection(md, 'Company Overview');
  if (!overview) return '';

  const match = overview.match(/Company Name:\s*(.*)/i);
  return match ? match[1].trim() : '';
}
function extractSection(text, heading) {
  const chunks = text.split(/\n(?=# )/);
  for (const chunk of chunks) {
    const firstLine = chunk.split('\n')[0].trim();
    const title = firstLine.replace(/^#+\s*/, '');
    if (title.toLowerCase() === heading.toLowerCase()) {
      return chunk.trim();
    }
  }
  return '';
}
const compressed = [
  extractSection(md, 'Core Services'),
  extractSection(md, 'Target Audience'),
  extractSection(md, 'SEO Keywords'),
  extractSection(md, 'Prohibited Phrases & Clichés'),
  extractSection(md, 'Brand Voice & Messaging')
].filter(Boolean).join('\n\n---\n\n');
const gaRows = ga.rows ?? [];
const top5Sessions = gaRows
  .slice(0, 5)
  .map(r => `${r.dimensionValues?.[1]?.value ?? 'Unknown'}: ${r.metricValues?.[0]?.value ?? 0} sessions`)
  .join('\n');
const top5Bounce = [...gaRows]
  .sort((a, b) => parseFloat(b.metricValues?.[1]?.value ?? 0) - parseFloat(a.metricValues?.[1]?.value ?? 0))
  .slice(0, 5)
  .map(r => `${r.dimensionValues?.[1]?.value ?? 'Unknown'}: ${(parseFloat(r.metricValues?.[1]?.value ?? 0) * 100).toFixed(0)}% bounce`)
  .join('\n');
const gaSummary = gaRows.length > 0
  ? `Top pages by sessions:\n${top5Sessions}\n\nHigh-bounce pages (content gaps):\n${top5Bounce}`
  : 'Analytics data unavailable — proceed without gap analysis';
const AI_KEYWORDS = [
  'ai', 'artificial intelligence', 'machine learning', 'ml', 'llm',
  'automation', 'automat', 'chatgpt', 'generative', 'genai', 'gpt',
  'agentic', 'agent', 'copilot', 'workflow', 'saas', 'digital',
  'enterprise software', 'productivity', 'cloud', 'data analytics',
  'prompt', 'openai', 'gemini', 'claude', 'chatbot', 'robotic',
  'rpa', 'nlp', 'deep learning', 'neural', 'digital transformation',
  'business automation', 'ai tools', 'ai strategy', 'technology'
];
function parseTrendItems(xml) {
  const items = [];
  const itemRe = /<item>([\s\S]*?)<\/item>/g;
  let m;
  while ((m = itemRe.exec(xml)) !== null) {
    const itemXml = m[1];
    const titleM   = itemXml.match(/<title>(?:<!\[CDATA\[)?(.*?)(?:\]\]>)?<\/title>/);
    const trafficM = itemXml.match(/<ht:approx_traffic>(.*?)<\/ht:approx_traffic>/);
    const newsTitles = [...itemXml.matchAll(/<ht:news_item_title>(?:<!\[CDATA\[)?(.*?)(?:\]\]>)?<\/ht:news_item_title>/g)]
      .map(n => n[1].trim());
    if (titleM) {
      items.push({
        title:       titleM[1].trim(),
        traffic:     trafficM ? parseInt(trafficM[1].replace(/[^0-9]/g, '')) || 0 : 0,
        newsTitles
      });
    }
  }
  return items;
}
function isRelevant(item) {
  const searchText = (item.title + ' ' + item.newsTitles.join(' ')).toLowerCase();
  return AI_KEYWORDS.some(kw => searchText.includes(kw));
}
const allTrends   = parseTrendItems(trends);
const aiTrends    = allTrends.filter(isRelevant).sort((a, b) => b.traffic - a.traffic);
const topAiTrends = aiTrends.slice(0, 8);
let trendsSummary;
if (topAiTrends.length > 0) {
  const lines = topAiTrends.map(t => {
    const traffic = t.traffic >= 1000 ? `${(t.traffic/1000).toFixed(0)}k+` : `${t.traffic}+`;
    const context = t.newsTitles[0] ? ` — "${t.newsTitles[0].slice(0, 80)}"` : '';
    return `  • ${t.title} (${traffic} searches)${context}`;
  }).join('\n');
  trendsSummary = `AI & tech topics trending in India right now:\n${lines}`;
} else {
  trendsSummary = `No AI/tech topics in today's Google Trends India feed (trending topics are unrelated: ${allTrends.slice(0,5).map(t => t.title).join(', ')}). Use evergreen AI business topics relevant to Indian enterprises instead.`;
}
const BATCH_SECTIONS  = ['Core Services', 'Target Audience', 'Customer Pain Points', 'Value Propositions', 'Key Content Topics'];
const GUIDES_SECTIONS = [...BATCH_SECTIONS, 'Competitor Differentiation'];
const batchWritingContext  = BATCH_SECTIONS.map(s  => extractSection(md, s)).filter(Boolean).join('\n\n');
const guidesWritingContext = GUIDES_SECTIONS.map(s => extractSection(md, s)).filter(Boolean).join('\n\n');
const toneBlock = ['Brand Voice & Messaging', 'Prohibited Phrases & Clichés']
  .map(s => extractSection(md, s)).filter(Boolean).join('\n\n');

const companyName = extractCompanyName(md);
return [{
  json: {
    companyName: companyName,
    compressed_brand:      compressed,
    full_brand:            md,
    batch_writing_context: batchWritingContext,
    guides_writing_context: guidesWritingContext,
    tone_block:            toneBlock,
    ga_summary:            gaSummary,
    trends_summary:        trendsSummary,
    trends_ai_count:       topAiTrends.length,
    trends_total_count:    allTrends.length,
    run_date:              new Date().toISOString().split('T')[0]
  }
}];

const compressedBrand = $input.first().json.compressed_brand;
const companyName = $input.first().json.companyName;
const gaSummary = $input.first().json.ga_summary;
const trendsSummary = $input.first().json.trends_summary;

const prompt = {
  "systemInstruction": "You are a senior AI content strategist. Return ONLY valid JSON with no preamble, no markdown fences, and no explanation.",
  "userMessage": `You are planning monthly AI marketing content for ${companyName} — an IT consulting agency with four service pillars: AI Strategy Consulting, AI Training & Fluency, Agentic AI Systems, Business Automation.

Brand context (compressed):
${compressedBrand}

Website analytics summary:
${gaSummary}

Trending topics this month:
${trendsSummary}

Instructions:
- Use analytics high-bounce pages to identify content gaps — prioritize filling those gaps.
- Use trending topics to rank ideas by rising search interest.
- Distribute content evenly across all 4 pillars. No pillar should have more than 2 blog topics.
- Blog primary keywords must be search-viable and non-branded.
- LinkedIn hooks must be specific — no openers starting with "AI is transforming..." or "In today's world...".
- Long-tail keywords must include intent signals: "how to", "for enterprise", "ROI of", or comparison terms.
- Never use these phrases: game-changer, leverage, unlock potential, cutting-edge, seamless, robust, disruptive.

Return ONLY this JSON schema — no other text:
{
  "strategy_overview": "2-3 sentence summary citing specific gaps or trends identified",
  "blog_topics": [
    {"title": "", "primary_keyword": "", "content_pillar": "AI Strategy|AI Training|Agentic AI|Automation", "target_persona": "CTO|Operations Leader|Innovation Builder|L&D Manager"}
  ],
  "linkedin_posts": [
    {"topic": "", "hook": "", "content_pillar": "AI Strategy|AI Training|Agentic AI|Automation"}
  ],
  "social_posts": [
    {"topic": "", "format": "tip|stat|question|checklist"}
  ],
  "email_topics": [
    {"subject": "", "content_pillar": "AI Strategy|AI Training|Agentic AI|Automation"}
  ],
  "guides": [
    {"title": "", "content_pillar": "AI Strategy|AI Training|Agentic AI|Automation"}
  ],
  "keyword_clusters": {
    "ai_strategy": [],
    "agentic_ai": [],
    "automation": [],
    "ai_training": []
  },
  "long_tail_keywords": []
}

Counts required: 6 blog_topics, 12 linkedin_posts, 8 social_posts, 4 email_topics, 4 guides, 5-8 terms per keyword cluster, 10 long_tail_keywords.`,
  "generationConfig": {
    "temperature": 0.4,
    "maxOutputTokens": 8192,
    "responseMimeType": "application/json",
    thinkingConfig: {
      thinkingBudget: 0
    }
  }
};

return { json: prompt };

const response = $input.all()[0].json;
if (response?.error) {
  throw new Error('Gemini API error: ' + JSON.stringify(response.error));
}
const rawText = response?.content?.parts?.[0]?.text ?? '';
const finishReason = response?.finish_reason ?? 'UNKNOWN';
if (!rawText) {
  throw new Error('Gemini returned empty content. Full response: ' + JSON.stringify(response).slice(0, 500));
}
let text = rawText.replace(/^```json\s*/m, '').replace(/\s*```$/m, '').trim();
if ((text.startsWith('"') && text.endsWith('"')) ||
    (text.startsWith("'") && text.endsWith("'"))) {
  text = text.slice(1, -1)
    .replace(/\\"/g, '"')
    .replace(/\\n/g, '\n')
    .replace(/\\\\/g, '\\');
}
let plan = null;
let parseError = null;
try {
  plan = JSON.parse(text);
  if (typeof plan === 'string') {
    plan = JSON.parse(plan);
  }
} catch (e) {
  parseError = e.message;
  plan = null;
}
if (!plan || typeof plan !== 'object' || Array.isArray(plan)) {
  function extractArray(src, key) {
    const re = new RegExp('"' + key + '"\\s*:\\s*(\\[[\\s\\S]*?\\])(?=\\s*[,}])', '');
    const m = src.match(re);
    if (m) {
      try { return JSON.parse(m[1]); } catch (e) { return null; }
    }
    return null;
  }
  function extractString(src, key) {
    const re = new RegExp('"' + key + '"\\s*:\\s*"((?:[^"\\\\]|\\\\.)*)"');
    const m = src.match(re);
    return m ? m[1] : null;
  }
  plan = {
    strategy_overview:  extractString(text, 'strategy_overview') || 'Strategy overview unavailable (response truncated)',
    blog_topics:        extractArray(text, 'blog_topics')        || [],
    linkedin_posts:     extractArray(text, 'linkedin_posts')     || [],
    social_posts:       extractArray(text, 'social_posts')       || [],
    email_topics:       extractArray(text, 'email_topics')       || [],
    guides:             extractArray(text, 'guides')             || [],
    keyword_clusters:   extractArray(text, 'keyword_clusters')   || {},
    long_tail_keywords: extractArray(text, 'long_tail_keywords') || []
  };
}
const required = [
  ['blog_topics', 6],
  ['linkedin_posts', 12],
  ['social_posts', 8],
  ['email_topics', 4],
  ['guides', 4]
];
const failures = required
  .filter(([key, count]) => !Array.isArray(plan[key]) || plan[key].length < count)
  .map(([key, count]) => key + ': expected ' + count + ', got ' + (plan[key]?.length ?? 0));
if (failures.length > 0) {
  const hint = finishReason === 'MAX_TOKENS'
    ? ' Gemini hit MAX_TOKENS — increase maxOutputTokens or reduce prompt size.'
    : '';
  throw new Error(
    'Content plan validation failed:' + hint + '\n' +
    failures.join('\n') +
    '\n\nfinishReason: ' + finishReason +
    '\nRaw output (first 600 chars):\n' + rawText.slice(0, 600)
  );
}
return [{ json: { content_plan: plan, finish_reason: finishReason } }];

const companyName = $('Compress Brand Context').first().json.companyName;
const plan          = $('Validate Content Plan').first().json.content_plan;
const guidesContext = $('Compress Brand Context').first().json.guides_writing_context;
const toneBlock     = $('Compress Brand Context').first().json.tone_block;

const guideTopics = JSON.stringify(plan.guides, null, 2);
const user_prompt = `Brand context:
${guidesContext}

---

Write all 4 AI guides for these topics:
${guideTopics}

Each guide must include:
- Title and subtitle
- Executive summary (100 words)
- 5-7 structured H2 sections
- A framework or decision model where applicable
- 2-3 realistic business scenarios (no invented company names)
- Common mistakes section
- Recommended next steps (numbered list)
- How [Your Brand] can help (2-3 sentences, brief and non-pushy)

Target length: 1800-2000 words each.
Separate each guide with: --- GUIDE BREAK ---
Label each: GUIDE 1: [Title], GUIDE 2: [Title], etc.`
const prompt = {
  "systemInstruction": `You are a senior AI strategist and writer for ${companyName}.
Write authoritative, practical guides for business leaders making investment decisions.
Tone: direct, data-informed, results-focused.

TONE & VOICE:
${toneBlock}`,
  "userMessage": user_prompt,
  generationConfig: {
    temperature: 0.6,
    maxOutputTokens: 8192,
    thinkingConfig: {
      thinkingBudget: 0
    }
  }
};

return { json: prompt };

const response = $input.first().json;
if (response?.error) {
  throw new Error('Gemini batch call API error: ' + JSON.stringify(response.error));
}

// Gemini node in n8n may return parsed JSON directly or as a text string
let parsed;

if (response.blog_articles || response.linkedin_posts) {
  // n8n already parsed the JSON (responseMimeType: application/json)
  parsed = response;
} else {
  // Fallback: extract raw text and parse manually
  const raw = response?.[0]?.content?.parts?.[0]?.text
           ?? response?.content?.parts?.[0]?.text
           ?? '';

  if (!raw) {
    throw new Error('Gemini: Write Batch Content returned empty. Check API key, quota, and node output.');
  }

  try {
    const clean = raw.replace(/```json|```/g, '').trim();
    parsed = JSON.parse(clean);
  } catch (e) {
    throw new Error('Failed to parse Gemini JSON response: ' + e.message + '\n\nRaw preview: ' + raw.substring(0, 300));
  }
}

// Validate expected sections
const warnings = [];
if (!Array.isArray(parsed.blog_articles)     || parsed.blog_articles.length === 0)     warnings.push('blog_articles missing or empty');
if (!Array.isArray(parsed.linkedin_posts)    || parsed.linkedin_posts.length === 0)     warnings.push('linkedin_posts missing or empty');
if (!Array.isArray(parsed.social_posts)      || parsed.social_posts.length === 0)       warnings.push('social_posts missing or empty');
if (!Array.isArray(parsed.email_newsletters) || parsed.email_newsletters.length === 0)  warnings.push('email_newsletters missing or empty');

// Validate counts
if (parsed.blog_articles?.length     !== 6)  warnings.push(`blog_articles count is ${parsed.blog_articles?.length}, expected 6`);
if (parsed.linkedin_posts?.length    !== 12) warnings.push(`linkedin_posts count is ${parsed.linkedin_posts?.length}, expected 12`);
if (parsed.social_posts?.length      !== 8)  warnings.push(`social_posts count is ${parsed.social_posts?.length}, expected 8`);
if (parsed.email_newsletters?.length !== 4)  warnings.push(`email_newsletters count is ${parsed.email_newsletters?.length}, expected 4`);

if (warnings.length > 0) {
  console.warn('Parse Batch Sections warnings: ' + warnings.join(', '));
}

return [{
  json: {
