const NAVY='1E3A5F', BLUE='2E75B6', LBLUE='EBF3FB', ALT='F5F7FA';
const BODY='444444', MUTED='777777', WHITE='FFFFFF', CHARCOAL='2B2B2B';

const esc = s => String(s||'').replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;');

function rPr(o){
  o=o||{};
  return `<w:rPr>${o.bold?'<w:b/>':''}${o.italic?'<w:i/>':''}<w:color w:val="${o.color||BODY}"/><w:sz w:val="${o.size||22}"/><w:szCs w:val="${o.size||22}"/><w:rFonts w:ascii="${o.font||'Calibri'}" w:hAnsi="${o.font||'Calibri'}" w:cs="${o.font||'Calibri'}"/></w:rPr>`;
}

function run(text,o){ return `<w:r>${rPr(o)}<w:t xml:space="preserve">${esc(text)}</w:t></w:r>`; }

function para(runs,o){
  o=o||{};
  const sb=o.spaceBefore!==undefined?o.spaceBefore:60, sa=o.spaceAfter!==undefined?o.spaceAfter:60;
  const jc=o.align?`<w:jc w:val="${o.align}"/>`:'';
  const sp=`<w:spacing w:before="${sb}" w:after="${sa}"/>`;
  const bd=o.borderBottom?`<w:pBdr><w:bottom w:val="single" w:sz="8" w:space="4" w:color="${o.borderBottom}"/></w:pBdr>`:'';
  return `<w:p><w:pPr>${bd}${sp}${jc}</w:pPr>${Array.isArray(runs)?runs.join(''):runs}</w:p>`;
}

const h1 = t => para(run(t,{bold:true,color:NAVY,size:32}),{spaceBefore:240,spaceAfter:80,borderBottom:BLUE});
