const numP    = (t,nid) => `<w:p><w:pPr><w:numPr><w:ilvl w:val="0"/><w:numId w:val="${nid||2}"/></w:numPr><w:spacing w:before="40" w:after="40"/></w:pPr>${run(t,{color:BODY,size:22})}</w:p>`;
