function cell(text,width,fill,bold,color){
  fill=fill||WHITE; bold=bold||false; color=color||CHARCOAL;
  const shd=`<w:shd w:val="clear" w:color="auto" w:fill="${fill}"/>`;
  const bdr=`<w:tcBorders><w:top w:val="single" w:sz="2" w:color="D0D9E3"/><w:bottom w:val="single" w:sz="2" w:color="D0D9E3"/><w:left w:val="single" w:sz="2" w:color="D0D9E3"/><w:right w:val="single" w:sz="2" w:color="D0D9E3"/></w:tcBorders>`;
  const mar=`<w:tcMar><w:top w:w="80" w:type="dxa"/><w:bottom w:w="80" w:type="dxa"/><w:left w:w="140" w:type="dxa"/><w:right w:w="140" w:type="dxa"/></w:tcMar>`;
  const p=para(run(text,{bold,color,size:20}),{spaceBefore:0,spaceAfter:0});
  return `<w:tc><w:tcPr><w:tcW w:w="${width}" w:type="dxa"/>${bdr}${shd}${mar}</w:tcPr>${p}</w:tc>`;
}
