let gNumId=2;

function parseMdTable(lines, startIdx){
  const tableLines=[];
  let i=startIdx;
  while(i<lines.length && lines[i].trim().startsWith('|')){
    tableLines.push(lines[i].trim());
    i++;
  }
  if(tableLines.length<2) return {xml:'',endIdx:startIdx+1};

  const headerCells=tableLines[0].split('|').map(c=>c.trim()).filter(c=>c.length>0);
  const dataRows=[];
  for(let r=2;r<tableLines.length;r++){
    const cells=tableLines[r].split('|').map(c=>c.trim()).filter(c=>c.length>0);
    if(cells.length>0) dataRows.push(cells);
  }

  const numCols=headerCells.length;
  const colW=Math.floor(9360/numCols);
  const cols=Array(numCols).fill(colW);
  cols[numCols-1]=9360-colW*(numCols-1);

  const grid=cols.map(w=>`<w:gridCol w:w="${w}"/>`).join('');
  const hdrRow=trow(headerCells.map((c,ci)=>hCell(c.replace(/\*\*(.+?)\*\*/g,'$1'),cols[ci])));
  const dataRowsXml=dataRows.map((row,ri)=>
    trow(cols.map((_,ci)=>{
      const txt=(row[ci]||'').replace(/\*\*(.+?)\*\*/g,'$1').replace(/^:?-+:?$/,'');
      return cell(txt,cols[ci],ri%2?ALT:WHITE);
    }))
  );
  const xml=`<w:tbl><w:tblPr><w:tblW w:w="9360" w:type="dxa"/><w:tblLayout w:type="fixed"/><w:tblCellMar><w:top w:w="0" w:type="dxa"/><w:bottom w:w="0" w:type="dxa"/></w:tblCellMar></w:tblPr><w:tblGrid>${grid}</w:tblGrid>${hdrRow}${dataRowsXml.join('')}</w:tbl>`;
  return {xml, endIdx:i};
}

function renderContent(text){
  if(!text) return spacerP();
  const out=[];
  const lines=text.split('\n');
  let i=0;
  let prevWasNum=false;
  while(i<lines.length){
    const line=lines[i];
    const t=line.trim();

    if(t.startsWith('|') && t.endsWith('|') && t.length>2){
      const result=parseMdTable(lines,i);
      if(result.xml){ out.push(spacerP(),result.xml,spacerP()); i=result.endIdx; continue; }
    }
    i++;

    if(!t||/^[=─\-]{10,}$/.test(t)){ continue; }
    if(/^\d+\.\s+[A-Z][A-Z\s&]+$/.test(t)){ continue; }
    if(/^[{\[\]},]/.test(t)){ continue; }
    if(/^"[a-z_]+"\s*:/.test(t)){ continue; }
    if(/^"[^"]+",?$/.test(t) && !t.includes(' \u2014 ') && !t.includes(': ')){ continue; }
    if(/^\|[-:\s|]+\|$/.test(t)){ continue; }
    if(/^[+\-]{4,}/.test(t)){ continue; }
    if(/^`{3}/.test(t)){ continue; }
    if(/^[\s|^v<>+\-]+$/.test(t) && /[|^v<>+]/.test(t) && !t.includes(':')){ continue; }

    if(t.startsWith('#### ')){ out.push(h4(t.slice(5))); continue; }
    if(t.startsWith('### ')){ out.push(h3(t.slice(4))); continue; }
    if(t.startsWith('## ')){ out.push(h2(t.slice(3))); continue; }

    if(/^--- (ARTICLE|POST|EMAIL|GUIDE) BREAK ---$/i.test(t)){ out.push(dividerP()); continue; }
    if(/^(ARTICLE|POST|SOCIAL|EMAIL|GUIDE)\s+\d+/i.test(t)){
      out.push(h2(t)); prevWasNum=false;
      continue;
    }

    if(t.startsWith('Meta description:') || t.startsWith('SEO Title:')){ out.push(mutedP(t)); continue; }

    if(t==='Introduction' || t==='Introduction:'){
      out.push(para(run('Introduction',{bold:true,color:BLUE,size:22}),{spaceBefore:120,spaceAfter:40}));
      continue;
    }
    if(t==='Key Takeaways' || t==='Key Takeaways:'){
      out.push(para(run('Key Takeaways',{bold:true,color:NAVY,size:22}),{spaceBefore:160,spaceAfter:60,borderBottom:LBLUE}));
      continue;
    }
    if(t.startsWith('Executive Summary:') || t==='Executive Summary'){
      out.push(para(run('Executive Summary',{bold:true,color:NAVY,size:22}),{spaceBefore:160,spaceAfter:60,borderBottom:LBLUE}));
      continue;
    }
    if(/^(Subject|Preview Text|Preview text):/.test(t)){
      const ci=t.indexOf(':');
      out.push(labelValueP(t.slice(0,ci),t.slice(ci+1).trim()));
      continue;
    }
    if(t.startsWith('Actionable Takeaway:')){
      out.push(takeawayP(t.slice(20).trim()));
      continue;
    }
    if(t.startsWith('Quick Tip:')){
      out.push(`<w:p><w:pPr><w:spacing w:before="80" w:after="80"/><w:shd w:val="clear" w:color="auto" w:fill="${LBLUE}"/></w:pPr>${run('Quick Tip: ',{bold:true,color:NAVY,size:20})}${run(t.slice(10).trim(),{color:CHARCOAL,size:20})}</w:p>`);
      continue;
    }
    if(t.startsWith('How [Your Brand] Can Help') || t.startsWith('How [Your Company Name] Can Help:')){
      out.push(para(run('How [Your Brand] Can Help',{bold:true,color:NAVY,size:22}),{spaceBefore:160,spaceAfter:60,borderBottom:BLUE}));
      continue;
    }
    if(t.startsWith('Recommended Next Steps') || t.startsWith('Recommended Next Steps:')){
      out.push(para(run('Recommended Next Steps',{bold:true,color:NAVY,size:22}),{spaceBefore:160,spaceAfter:60,borderBottom:BLUE}));
      continue;
    }

    if(/^\d+[\.\)]\s/.test(t)){
      if(!prevWasNum){ gNumId++; if(gNumId>51) gNumId=3; }
      prevWasNum=true;
      out.push(numP(t.replace(/^\d+[\.\)]\s+/,'').replace(/\*\*(.+?)\*\*/g,'$1'), gNumId));
      continue;
    }
    if(/^[\*\-\u2022]\s/.test(t)){ out.push(bulletP(t.slice(2).replace(/\*\*(.+?)\*\*/g,'$1'))); continue; }

    if(t.startsWith('#') && t.includes(' ') && !t.startsWith('##')){
      out.push(para(run(t,{color:BLUE,size:20,italic:true}),{spaceBefore:40,spaceAfter:80}));
      continue;
    }

    if(/^(Sincerely|Best regards),?$/.test(t)){
      out.push(para(run(t,{color:MUTED,size:22,italic:true}),{spaceBefore:80,spaceAfter:20}));
      continue;
    }
    if(t==='The [Your Brand] Team'){
      out.push(para(run(t,{bold:true,color:NAVY,size:22}),{spaceBefore:0,spaceAfter:80}));
      continue;
    }

    prevWasNum=false; out.push(bodyP(t.replace(/\*\*(.+?)\*\*/g,'$1')));
  }
  return out.join('');
}

function getSection(text, num){
  const parts = text.split(/\n+={10,}\n+/);
  for(const part of parts){
    if(part.trim().split('\n')[0].trim().match(new RegExp('^'+num+'\\.\\s'))){
      let body = part.trim()
        .replace(/^[^\n]+\n+[-─]{5,}[^\n]*\n+/, '')
        .trim();
      if(body.startsWith('{') || body.startsWith('"')){
        body = body.replace(/^[\s\S]*?\}\s*\n/, '').trim();
      }
      return body;
    }
  }
  return '';
}

function getStrategy(text){
  const parts = text.split(/\n+={10,}\n+/);
  for(const part of parts){
    if(part.trim().split('\n')[0].trim().startsWith('1. MONTHLY')){
      let body = part.trim()
        .replace(/^[^\n]+\n+[-─]{5,}[^\n]*\n+/, '')
        .trim();
      body = body.replace(/^[\s\S]*?\}\s*\n/, '').trim();
      return body;
    }
  }
  return '';
}

