function strToBytes(str){
  const out=[];
  for(let i=0;i<str.length;i++){
    let c=str.charCodeAt(i);
    if(c>=0xD800 && c<=0xDBFF){
      const hi=c, lo=str.charCodeAt(i+1);
      if(lo>=0xDC00 && lo<=0xDFFF){
        c=0x10000+((hi-0xD800)<<10)+(lo-0xDC00);
        i++; 
      }
    }
    if(c<0x80){             out.push(c); }
    else if(c<0x800){       out.push(0xC0|(c>>6),  0x80|(c&0x3F)); }
    else if(c<0x10000){     out.push(0xE0|(c>>12), 0x80|((c>>6)&0x3F), 0x80|(c&0x3F)); }
    else{                   out.push(0xF0|(c>>18), 0x80|((c>>12)&0x3F), 0x80|((c>>6)&0x3F), 0x80|(c&0x3F)); }
  }
  return out;
}

function crc32(bytes){
  const t=[];
  for(let i=0;i<256;i++){let x=i;for(let j=0;j<8;j++)x=(x&1)?(0xEDB88320^(x>>>1)):(x>>>1);t[i]=x;}
  let c=0xFFFFFFFF;
  for(let i=0;i<bytes.length;i++) c=t[(c^bytes[i])&0xFF]^(c>>>8);
  return(c^0xFFFFFFFF)>>>0;
}

const u16 = n => [n&0xFF,(n>>8)&0xFF];
const u32 = n => [n&0xFF,(n>>8)&0xFF,(n>>16)&0xFF,(n>>24)&0xFF];

function buildZip(fileMap){
  const entries=Object.entries(fileMap);
  const locals=[],central=[];
  let offset=0;
  for(const[name,content] of entries){
    const nb=strToBytes(name), d=strToBytes(content), crc=crc32(d), sz=d.length;
    const loc=[0x50,0x4B,0x03,0x04,...u16(20),...u16(0),...u16(0),...u16(0),...u16(0),...u32(crc),...u32(sz),...u32(sz),...u16(nb.length),...u16(0),...nb,...d];
    central.push([0x50,0x4B,0x01,0x02,...u16(20),...u16(20),...u16(0),...u16(0),...u16(0),...u16(0),...u32(crc),...u32(sz),...u32(sz),...u16(nb.length),...u16(0),...u16(0),...u16(0),...u16(0),...u32(0),...u32(offset),...nb]);
    locals.push(loc);
    offset+=loc.length;
  }
  const cf=central.flat();
  const eocd=[0x50,0x4B,0x05,0x06,...u16(0),...u16(0),...u16(entries.length),...u16(entries.length),...u32(cf.length),...u32(offset),...u16(0)];
  const all=[...locals.flat(),...cf,...eocd];

  const B64='ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789+/';
  let b64='';
  const len=all.length;
  for(let i=0;i<len;i+=3){
    const b0=all[i], b1=i+1<len?all[i+1]:0, b2=i+2<len?all[i+2]:0;
    b64+=B64[b0>>2]+B64[((b0&3)<<4)|(b1>>4)]+B64[((b1&15)<<2)|(b2>>6)]+B64[b2&63];
  }
  const pad=len%3;
  if(pad===1)      b64=b64.slice(0,-2)+'==';
  else if(pad===2) b64=b64.slice(0,-1)+'=';
  return b64;
}

