    }
    if (targetKey) {
      try {
        const buffer = await this.helpers.getBinaryDataBuffer(i, targetKey);
        const xmlString = buffer.toString('utf8');
        extractedText = xmlString
          .replace(/<w:p[ >]/g, '\n<w:p ')
          .replace(/<[^>]+>/g, '')
          .replace(/&amp;/g, '&')
          .replace(/&lt;/g, '<')
          .replace(/&gt;/g, '>')
          .replace(/&quot;/g, '"')
          .replace(/&apos;/g, "'")
          .replace(/\n{3,}/g, '\n\n')
          .trim();
      } catch (error) {
        extractedText = '[Error reading file buffer: ' + error.message + ']';
      }
    }
  }
  returnItems.push({
    json: {
      text: extractedText,
      fileName: originalFileName,
      charCount: extractedText.length
    }
  });
}
return returnItems;

const returnItems = [];
const items = $input.all();
const now = new Date();
const convertToHtml = (text) => {
  const lines = text.split('\n');
  let html = '';
  for (let i = 0; i < lines.length; i++) {
    const line = lines[i].trim();
    if (!line) continue;
    if (/^(Step\s+\d+|What|How|Why|When)/i.test(line) || line.endsWith('?')) {
      html += `<h3>${line}</h3>\n`;
    } else {
      html += `<p>${line}</p>\n`;
    }
  }
  return html.trim();
};
let articleIndex = 0;

const MIN_BUFFER_SECONDS = 15 * 60; // 15 min safety margin
const MAX_SCHEDULE_SECONDS = 74 * 24 * 60 * 60; // <75 days
const nowTs = Math.floor(Date.now() / 1000);
const clampTs = (ts) => Math.min(
  Math.max(ts, nowTs + MIN_BUFFER_SECONDS),
  nowTs + MAX_SCHEDULE_SECONDS
);

for (const item of items) {
  const chunks = item.json.text.split(/(?=ARTICLE\s+\d+\s*:)/i);
  for (const chunk of chunks) {
    const block = chunk.trim();
    const articleMatch = block.match(/^ARTICLE\s+(\d+)\s*:\s*(.+)/i);
    if (articleMatch) {
      const articleTitle = articleMatch[2].split('\n')[0].trim();
      const scheduledDate = new Date(now.getFullYear(), now.getMonth(), 2 + (articleIndex * 5), 9, 0, 0);
      returnItems.push({
        json: {
          title: articleTitle,
          bodyHtml: convertToHtml(block),
          scheduledDate: scheduledDate.toISOString(),
          scheduledTimestamp: clampTs(Math.floor(scheduledDate.getTime() / 1000))
        }
      });
      articleIndex++;
    }
  }
}
return returnItems;

