const linkedInPosts = [];
const now = new Date();
const linkedInRegex = /POST \d+:\n(.*?)\n([\s\S]*?)(?=\nPOST \d+:|\n\d+\.\s|(\n)?$)/g;
let match; let postIndex = 0;

const MIN_BUFFER_SECONDS = 15 * 60; // 15 min safety margin
const MAX_SCHEDULE_SECONDS = 74 * 24 * 60 * 60; // <75 days
const nowTs = Math.floor(Date.now() / 1000);
const clampTs = (ts) => Math.min(
  Math.max(ts, nowTs + MIN_BUFFER_SECONDS),
  nowTs + MAX_SCHEDULE_SECONDS
);

while ((match = linkedInRegex.exec(text)) !== null) {
  const topic = match[1].trim();
  const content = match[2].trim();
  if (topic && content) {
    const scheduledDate = new Date(now.getFullYear(), now.getMonth(), 2 + (postIndex * 5), 10, 0, 0);
    linkedInPosts.push({ json: { topic, content, scheduledDate: scheduledDate.toISOString(), scheduledTimestamp: clampTs(Math.floor(scheduledDate.getTime() / 1000)) } });
    postIndex++;
  }
}
return linkedInPosts;

const text = $input.first().json.text;
const educationalPosts = [];
const socialRegex = /SOCIAL \d+:\s*(.*?)\n([\s\S]*?)(?=\nSOCIAL \d+:|\n5\. Email|(\n)?$)/g;
let match;
const now = new Date();
let postIndex = 0;

const MIN_BUFFER_SECONDS = 15 * 60; // 15 min safety margin
const MAX_SCHEDULE_SECONDS = 74 * 24 * 60 * 60; // <75 days
const nowTs = Math.floor(Date.now() / 1000);
const clampTs = (ts) => Math.min(
  Math.max(ts, nowTs + MIN_BUFFER_SECONDS),
  nowTs + MAX_SCHEDULE_SECONDS
);

while ((match = socialRegex.exec(text)) !== null) {
  const type = match[1].trim();
  let content = match[2].trim();
  if (type && content) {
      const scheduledDate = new Date(now.getFullYear(),now.getMonth(), 2 + (postIndex * 5), 10, 0, 0);
    educationalPosts.push({
      json: {
        type: type,
        content: content,
        scheduledDate: scheduledDate.toISOString(),
        scheduledTimestamp: clampTs(Math.floor(scheduledDate.getTime() / 1000))
      }
    });
    postIndex++;
  }
}
return educationalPosts;

const errorNodes = [];
const emailOut = $input.first()?.json;
if (emailOut?.error) {
  errorNodes.push({ node: 'Send Notification Email', error: String(emailOut.error) });
}
if (emailOut?.statusCode && emailOut.statusCode >= 400) {
  errorNodes.push({ node: 'Send Notification Email', error: `HTTP ${emailOut.statusCode}` });
}
try {
  const uploadOut = $('Upload to Drive').first()?.json;
  if (uploadOut?.error) {
    errorNodes.push({ node: 'Upload DOCX to Google Drive', error: String(uploadOut.error) });
  }
} catch(e) {}
try {
  const docxOut = $('Build DOCX').first()?.json;
  if (docxOut?.error) {
    errorNodes.push({ node: 'Generate Styled DOCX', error: String(docxOut.error) });
  }
} catch(e) { }
try {
  const assembleOut = $('Merge Content Output').first()?.json;
  if (assembleOut?.error) {
    errorNodes.push({ node: 'Assemble Document', error: String(assembleOut.error) });
  }
  if (!assembleOut?.assembled_content) {
    errorNodes.push({ node: 'Assemble Document', error: 'assembled_content is empty' });
  }
} catch(e) { }
try {
  const planOut = $('Generate Content Plan').first()?.json;
  if (planOut?.error) {
    errorNodes.push({ node: 'Generate Content Plan', error: JSON.stringify(planOut.error) });
  }
} catch(e) { }
try {
  const batchOut = $('Write Batch Content').first()?.json;
  if (batchOut?.error) {
    errorNodes.push({ node: 'Write Batch Content', error: JSON.stringify(batchOut.error) });
  }
} catch(e) { }
try {
  const guidesOut = $('Write Guides').first()?.json;
  if (guidesOut?.error) {
    errorNodes.push({ node: 'Write Guides', error: JSON.stringify(guidesOut.error) });
  }
} catch(e) { }
if (errorNodes.length > 0) {
  console.log('Pipeline errors detected:', JSON.stringify(errorNodes));
}
return [{
  json: {
    status: errorNodes.length === 0 ? 'SUCCESS' : 'COMPLETED_WITH_ERRORS',
    errors: errorNodes,
    error_count: errorNodes.length,
    completed_at: new Date().toISOString()
  }
}];

// ─────────────────────────────────────────────────────────────
// Assemble Document — CODE NODE (no AI call)
// Replaces: Gemini: Assemble Doc (was call 7)
// Document assembly is deterministic formatting — pure JavaScript.
// Zero cost, zero latency, no hallucination risk.
// ─────────────────────────────────────────────────────────────

const companyName = $('Compress Brand Context').first().json.companyName;
const batchData   = $('Parse Content Sections').first().json;
const guidesData  = $('Extract Guides').first().json;
const plan        = batchData.content_plan;
const runDate     = new Date().toLocaleDateString('en-IN', { month: 'long', year: 'numeric' });
const runDateUpper = runDate.toUpperCase();

const div  = '\n\n' + '='.repeat(60) + '\n\n';
const line = '─'.repeat(45);

// Build keyword clusters summary
let kwSummary = '';
if (plan.keyword_clusters) {
  kwSummary = Object.entries(plan.keyword_clusters)
    .map(([pillar, terms]) => `  ${pillar.replace(/_/g,' ').toUpperCase()}: ${Array.isArray(terms) ? terms.join(', ') : 'N/A'}`)
    .join('\n');
}

const toc =
`TABLE OF CONTENTS
${line}
1. Monthly Content Strategy Overview
2. SEO Blog Articles (6)
3. LinkedIn Thought Leadership Posts (12)
4. Educational Social Media Posts (8)
5. Email Newsletter Campaigns (4)
6. AI Strategy & Automation Guides (4)
7. Keyword Clusters & Long-Tail Keywords
${line}
Generated: ${runDate} | Pipeline: Tricore Infotech n8n (Optimized)`;

const assetSummary =
`ASSET SUMMARY
${line}
SEO Blog Articles .......... 6
LinkedIn Posts ............. 12
Social Media Posts ......... 8
Email Newsletters .......... 4
AI Guides .................. 4
${line}
Total pieces ............... 34

Strategy overview: ${plan.strategy_overview ?? 'See plan JSON below'}`;

const keywordSection =
`KEYWORD CLUSTERS
${line}
${kwSummary}

LONG-TAIL KEYWORDS
${line}
${Array.isArray(plan.long_tail_keywords) ? plan.long_tail_keywords.map((k, i) => `${i+1}. ${k}`).join('\n') : 'N/A'}`;

const warnings = batchData.parse_warnings ?? [];
const warningBlock = warnings.length > 0
  ? `\n\n⚠ PIPELINE WARNINGS\n${line}\n${warnings.join('\n')}\n`
  : '';

const assembled = [
  `${companyName} — AI CONTENT PACKAGE — ${runDateUpper}`,
  div,
  toc,
  div,
  assetSummary,
  warningBlock,
  div,
  '1. MONTHLY CONTENT STRATEGY OVERVIEW',
  line,
  JSON.stringify(plan, null, 2),
  div,
  '2. SEO BLOG ARTICLES',
  line,
  batchData.blog_articles,
  div,
  '3. LINKEDIN THOUGHT LEADERSHIP POSTS',
  line,
  batchData.linkedin_posts,
  div,
  '4. EDUCATIONAL SOCIAL MEDIA POSTS',
  line,
  batchData.social_posts,
  div,
  '5. EMAIL NEWSLETTER CAMPAIGNS',
  line,
  batchData.email_newsletters,
  div,
  '6. AI STRATEGY & AUTOMATION GUIDES',
  line,
  guidesData.ai_guides,
  div,
  '7. KEYWORD CLUSTERS & LONG-TAIL KEYWORDS',
  line,
  keywordSection
].join('\n\n');

return [{
  json: {
    assembled_content: assembled,
    doc_title: `${companyName} – AI Content Package – ${runDate}`,
    run_date: runDate,
    char_count: assembled.length,
    warnings: warnings,
    content_plan: plan
  }
}];
